const input = $input.first().json;
const query = (input.query || input.message || input.text || '').trim();
const chatId = (input.chatId || input.chat_id || '').toString();
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const today = now.toLocaleDateString('es-ES');
const hour = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');

// ══ CONFIG N8N API ══
const N8N_HOST = 'https://nexusys.duckdns.org';
const N8N_API_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiJhYzI0OGM2OC1iOGZiLTQ3ZGItOWVjMC1kOWQ0YmUxYTU3NzMiLCJpc3MiOiJuOG4iLCJhdWQiOiJwdWJsaWMtYXBpIiwianRpIjoiMzYzY2IzNzktOGIzMC00MzM3LWI5N2EtNGM4NGY1MmQ0ODg4IiwiaWF0IjoxNzcxOTA0NTI5fQ.-7m7aHO38-KgK8oQRdFLkq9YsD7_DFXjSSeIZ_kUVDs';

return [{ json: { 
  query, chatId, today, hour,
  n8n_host: N8N_HOST,
  api_key: N8N_API_KEY
} }];

const agentRaw = $input.first().json;
const parser = $('📦 Parser + Config').first().json;

let ai = {};
try {
  let text = agentRaw.text || agentRaw.output || agentRaw.message || '';
  if (typeof text === 'object') { ai = text; }
  else {
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) ai = JSON.parse(m[0]);
  }
} catch(e) { 
  ai = { action: 'list_workflows', params: {} }; 
}

const p = ai.params || {};

// Normalizar acción
let action = (ai.action || 'list_workflows').toLowerCase().trim();

// Si es fix_prompt o update_node, validar que tenemos los params necesarios
if (action === 'fix_prompt' || action === 'update_node') {
  if (!p.workflow_name && !p.workflow_id) {
    action = 'list_workflows'; // Fallback si falta info
  }
}

return [{ json: {
  action: action,
  intent_description: ai.intent_description || '',
  confidence: ai.confidence || 'medium',

  // Params específicos
  workflow_name: p.workflow_name || '',
  workflow_id: p.workflow_id || '',
  node_name: p.node_name || '',
  modification_type: p.modification_type || 'append',
  new_content: p.new_content || '',
  description: p.description || '',
  new_prompt: p.new_prompt || p.new_content || '',
  execution_id: p.execution_id || '',
  limit: p.limit || 10,
  status: p.status || 'all',

  // Contexto
  query: parser.query,
  chatId: parser.chatId,
  today: parser.today,
  hour: parser.hour,

  // API Config
  n8n_host: parser.n8n_host,
  api_key: parser.api_key
} }];

const data = $input.first().json;
const wfs = data.data || data || [];

// Verificar si hubo error HTTP
if (data.error || data.message) {
  return [{ json: { 
    _action: 'list_workflows', 
    error: true,
    summary: '❌ Error API: ' + (data.message || data.error || 'Error desconocido')
  } }];
}

const list = (Array.isArray(wfs) ? wfs : []).map(w => ({
  id: w.id, 
  name: w.name, 
  active: w.active,
  created: w.createdAt ? new Date(w.createdAt).toLocaleDateString('es-ES') : '',
  updated: w.updatedAt ? new Date(w.updatedAt).toLocaleDateString('es-ES') : '',
  nodes: w.nodes?.length || 0
}));

const active = list.filter(w => w.active).length;
const inactive = list.length - active;

return [{ json: { 
  _action: 'list_workflows', 
  total: list.length, 
  active, 
  inactive, 
  workflows: list, 
  summary: list.length + ' workflows: ' + active + ' activos, ' + inactive + ' inactivos' 
} }];

const data = $input.first().json;
const wfs = data.data || data || [];
const bridge = $('🔗 Bridge').first().json;
const search = (bridge.workflow_name || bridge.workflow_id || '').toLowerCase();

if (!search) {
  return [{ json: { error: true, _action: 'get_workflow', summary: '❌ No especificaste qué workflow ver' } }];
}

const found = (Array.isArray(wfs) ? wfs : []).find(w => 
  w.name.toLowerCase().includes(search) || w.id === search
);

if (!found) {
  return [{ json: { error: true, _action: 'get_workflow', summary: '❌ Workflow no encontrado: ' + search } }];
}

return [{ json: { workflowId: found.id, workflowName: found.name } }];

const wf = $input.first().json;

if (wf.error || !wf.id) {
  return [{ json: { _action: 'get_workflow', error: true, summary: '❌ Error al obtener workflow' } }];
}

const nodes = (wf.nodes || []).map(n => ({ 
  name: n.name, 
  type: n.type?.split('.').pop() || n.type 
}));

const agents = nodes.filter(n => n.type?.toLowerCase().includes('agent'));

let prompts = [];
(wf.nodes || []).forEach(n => {
  const sysMsg = n.parameters?.options?.systemMessage;
  if (sysMsg) {
    prompts.push({ 
      node: n.name, 
      promptPreview: sysMsg.substring(0, 300) + '...' 
    });
  }
});

return [{ json: {
  _action: 'get_workflow',
  id: wf.id, 
  name: wf.name, 
  active: wf.active,
  nodeCount: nodes.length, 
  nodes,
  agentCount: agents.length, 
  agents,
  prompts,
  summary: '"' + wf.name + '" — ' + nodes.length + ' nodos, ' + agents.length + ' agentes, ' + (wf.active ? '✅ activo' : '❌ inactivo')
} }];

const wfs = ($input.first().json.data || []);
const search = $('🔗 Bridge').first().json.workflow_name.toLowerCase();
const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) return [{ json: { error: true, _action: 'activate_wf', summary: '❌ Workflow no encontrado' } }];
return [{ json: { workflowId: found.id, workflowName: found.name, currentActive: found.active } }];

const r = $('🔧 Resolve Activate').first().json;
const resp = $input.first().json;
if (resp.error) return [{ json: { _action: 'activate_wf', error: true, summary: '❌ Error: ' + resp.message } }];
return [{ json: { _action: 'activate_wf', activated: true, name: r.workflowName, summary: '✅ "' + r.workflowName + '" activado correctamente.' } }];

const wfs = ($input.first().json.data || []);
const search = $('🔗 Bridge').first().json.workflow_name.toLowerCase();
const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) return [{ json: { error: true, _action: 'deactivate_wf', summary: '❌ Workflow no encontrado' } }];
return [{ json: { workflowId: found.id, workflowName: found.name } }];

const r = $('🔧 Resolve Deactivate').first().json;
const resp = $input.first().json;
if (resp.error) return [{ json: { _action: 'deactivate_wf', error: true, summary: '❌ Error: ' + resp.message } }];
return [{ json: { _action: 'deactivate_wf', deactivated: true, name: r.workflowName, summary: '⏸️ "' + r.workflowName + '" desactivado.' } }];

const wfs = ($input.first().json.data || []);
const search = $('🔗 Bridge').first().json.workflow_name.toLowerCase();
const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) return [{ json: { error: true, _action: 'execute_wf', summary: '❌ Workflow no encontrado' } }];
return [{ json: { workflowId: found.id, workflowName: found.name } }];

const data = $input.first().json;
const execs = data.data || data || [];
const list = (Array.isArray(execs) ? execs : []).slice(0, 15).map(e => ({
  id: e.id, 
  workflow: e.workflowData?.name || e.workflowId || '?',
  status: e.finished ? '✅' : '❌',
  startedAt: e.startedAt ? new Date(e.startedAt).toLocaleString('es-ES') : '',
  error: e.data?.resultData?.error?.message?.substring(0, 100) || ''
}));
const errors = list.filter(e => e.status === '❌').length;
return [{ json: { _action: 'get_executions', total: list.length, errors, executions: list, summary: list.length + ' ejecuciones recientes, ' + errors + ' con error' } }];

const exec = $input.first().json;
const error = exec.data?.resultData?.error || {};
return [{ json: {
  _action: 'get_execution',
  id: exec.id, 
  workflow: exec.workflowData?.name || '',
  finished: exec.finished, 
  status: exec.finished ? '✅' : '❌',
  error: error.message || 'Sin error',
  summary: 'Ejecución ' + exec.id + ': ' + (exec.finished ? '✅ OK' : '❌ Error: ' + (error.message || 'desconocido'))
} }];

const data = $input.first().json;
const execs = data.data || data || [];
const errors = (Array.isArray(execs) ? execs : []).map(e => ({
  id: e.id,
  workflow: e.workflowData?.name || e.workflowId || '?',
  workflowId: e.workflowId || e.workflowData?.id || '',
  error: e.data?.resultData?.error?.message || 'Error desconocido',
  time: e.startedAt ? new Date(e.startedAt).toLocaleString('es-ES') : ''
}));

return [{ json: {
  _action: 'debug_workflow',
  errorCount: errors.length,
  errors,
  summary: errors.length + ' errores recientes: ' + errors.map(e => e.workflow + ' → ' + e.error.substring(0, 60)).join(' | ')
} }];

const wfs = ($input.first().json.data || []);
const bridge = $('🔗 Bridge').first().json;
const search = (bridge.workflow_name || '').toLowerCase();

if (!search) {
  return [{ json: { error: true, _action: 'update_workflow', summary: '❌ No especificaste qué workflow modificar' } }];
}

const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) {
  return [{ json: { error: true, _action: 'update_workflow', summary: '❌ Workflow no encontrado: ' + search } }];
}

return [{ json: { 
  workflowId: found.id, 
  workflowName: found.name,
  nodeName: bridge.node_name,
  newContent: bridge.new_content,
  newPrompt: bridge.new_prompt,
  description: bridge.description,
  query: bridge.query
} }];

