parameters.jsCode:
const modified = $input.first().json;
const resolved = $('🔧 Resolve Update WF').first().json;

let wfJson = null;
try {
  let text = modified.output || modified.text || '';
  if (typeof text === 'object' && text.nodes) {
    wfJson = text;
  } else {
    // Limpiar markdown si existe
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) wfJson = JSON.parse(m[0]);
  }
} catch(e) {
  return [{ json: { 
    error: true, 
    _action: 'update_workflow', 
    summary: '❌ Error parseando JSON modificado: ' + e.message 
  } }];
}

if (!wfJson || !wfJson.nodes) {
  return [{ json: { 
    error: true, 
    _action: 'update_workflow', 
    summary: '❌ No se pudo generar el JSON modificado válido' 
  } }];
}

return [{ json: { 
  workflowId: resolved.workflowId, 
  workflowName: resolved.workflowName, 
  modifiedJson: wfJson 
} }];

const saveResult = $('💾 Save Updated WF').first().json;
const verifyResult = $input.first().json;
const parsed = $('🔧 Parse Modified WF').first().json;
const bridge = $('🔗 Bridge').first().json;

// Verificar si hubo error al guardar
if (saveResult.error || saveResult.message?.includes('error')) {
  return [{ json: { 
    _action: 'update_workflow', 
    error: true, 
    summary: '❌ Error al guardar: ' + (saveResult.message || 'Error desconocido')
  } }];
}

// Verificar que el workflow se actualizó
if (verifyResult.error) {
  return [{ json: { 
    _action: 'update_workflow', 
    error: true, 
    summary: '⚠️ Guardado pero no se pudo verificar'
  } }];
}

// Comparar si el cambio se aplicó (simplificado)
const nodeToCheck = bridge.node_name;
let changeVerified = false;
let verificationDetail = '';

if (nodeToCheck && verifyResult.nodes) {
  const node = verifyResult.nodes.find(n => n.name.toLowerCase().includes(nodeToCheck.toLowerCase()));
  if (node) {
    changeVerified = true;
    verificationDetail = 'Nodo "' + node.name + '" encontrado y actualizado.';
  }
} else {
  changeVerified = true;
  verificationDetail = 'Workflow actualizado.';
}

return [{ json: { 
  _action: 'update_workflow', 
  updated: true, 
  verified: changeVerified,
  name: parsed.workflowName, 
  summary: '✅ "' + parsed.workflowName + '" actualizado y verificado. ' + verificationDetail
} }];

const wfs = ($input.first().json.data || []);
const bridge = $('🔗 Bridge').first().json;
const search = (bridge.workflow_name || '').toLowerCase();

if (!search) {
  return [{ json: { error: true, _action: 'fix_prompt', summary: '❌ No especificaste qué workflow modificar' } }];
}

const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) {
  return [{ json: { error: true, _action: 'fix_prompt', summary: '❌ Workflow no encontrado: ' + search } }];
}

return [{ json: { 
  workflowId: found.id, 
  workflowName: found.name,
  nodeName: bridge.node_name,
  newPrompt: bridge.new_prompt || bridge.new_content,
  modificationType: bridge.modification_type || 'append',
  query: bridge.query
} }];

const modifyResult = $('🔧 Modify Prompt Directly').first().json;
const saveResult = $('💾 Save Fixed Prompt').first().json;
const verifyResult = $input.first().json;

if (saveResult.error) {
  return [{ json: { 
    _action: 'fix_prompt', 
    error: true, 
    summary: '❌ Error guardando: ' + (saveResult.message || 'Error')
  } }];
}

// Verificar que el prompt se actualizó
let verified = false;
if (verifyResult.nodes) {
  const node = verifyResult.nodes.find(n => n.name === modifyResult.nodeName);
  if (node) {
    const currentLength = node.parameters?.options?.systemMessage?.length || 0;
    verified = currentLength === modifyResult.promptLengthAfter;
  }
}

return [{ json: { 
  _action: 'fix_prompt', 
  updated: true,
  verified,
  workflowName: modifyResult.workflowName,
  nodeName: modifyResult.nodeName,
  modificationType: modifyResult.modificationType,
  promptGrowth: modifyResult.promptLengthAfter - modifyResult.promptLengthBefore,
  summary: verified 
    ? '✅ Prompt de "' + modifyResult.nodeName + '" actualizado en "' + modifyResult.workflowName + '" (+' + (modifyResult.promptLengthAfter - modifyResult.promptLengthBefore) + ' caracteres)'
    : '⚠️ Prompt guardado pero no se pudo verificar completamente'
} }];

const wfs = ($input.first().json.data || []);
const bridge = $('🔗 Bridge').first().json;
const search = (bridge.workflow_name || '').toLowerCase();

if (!search) {
  return [{ json: { error: true, _action: 'update_node', summary: '❌ No especificaste qué workflow modificar' } }];
}

const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) {
  return [{ json: { error: true, _action: 'update_node', summary: '❌ Workflow no encontrado: ' + search } }];
}

return [{ json: { 
  workflowId: found.id, 
  workflowName: found.name,
  nodeName: bridge.node_name,
  newContent: bridge.new_content,
  query: bridge.query
} }];

// ═══ RESPONSE BUILDER BLINDADO v2.0 ═══

const bridge = $('🔗 Bridge').first().json;
let data = {};

// ═══ INTENTAR OBTENER DATA DEL INPUT ═══
try {
  const raw = $input.first();
  if (raw && raw.json) {
    data = raw.json;
  }
} catch(e) {
  data = {};
}

// ═══ DETECTAR SI VIENE VACÍO ═══
const isEmpty = !data || Object.keys(data).length === 0;

// ═══ BUSCAR SUMMARY EN MÚLTIPLES FUENTES ═══
let summary = '';
let action = bridge.action || 'unknown';
let error = false;

if (!isEmpty) {
  summary = data.summary || data.toolResponse || data.textResponse || data.message || '';
  action = data._action || data.action || bridge.action || 'unknown';
  error = data.error || false;
}

// ═══ SI NO HAY SUMMARY, BUSCAR EN NODOS ANTERIORES ═══
if (!summary) {
  const nodesToCheck = [
    '📋 Format List',
    '📋 Format Get WF',
    '📋 Format Activate',
    '📋 Format Deactivate',
    '📋 Format Execute',
    '📋 Format Executions',
    '📋 Format Exec Detail',
    '📋 Format Debug',
    '📋 Format + Verify Update',
    '📋 Format Fix Prompt',
    '📋 Format Node Update',
    '📋 Create WF Info',
    '📋 Redirect Node/Prompt',
    '📋 Format Create WF',
    '📋 Format Delete'
  ];

  for (const nodeName of nodesToCheck) {
    try {
      const nodeData = $(nodeName).first();
      if (nodeData && nodeData.json && nodeData.json.summary) {
        summary = nodeData.json.summary;
        action = nodeData.json._action || action;
        error = nodeData.json.error || false;
        data = nodeData.json;
        break;
      }
    } catch(e) {
      // Nodo no existe en esta ejecución, saltar
      continue;
    }
  }
}

// ═══ FALLBACK FINAL ═══
if (!summary) {
  summary = '⚠️ Acción "' + action + '" procesada pero sin datos de respuesta.';
  error = true;
}

// ═══ CONSTRUIR RESPUESTA GARANTIZADA ═══
return [{ json: {
  action: action,
  intent_description: bridge.intent_description || '',
  query: bridge.query || '',
  chatId: bridge.chatId || '',
  today: bridge.today || '',
  hour: bridge.hour || '',
  summary: summary,
  data: isEmpty ? { summary: summary } : data,
  confidence: bridge.confidence || 'medium',
  error: error
} }];

