const raw = $input.first().json;
const builder = $('📊 Response Builder').first().json;

let final;
try {
  let text = raw.text || raw.output || raw.message || '';
  if (typeof text === 'object' && text.textResponse) { 
    final = text; 
  } else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) final = JSON.parse(m[0]); 
    else throw new Error('No JSON');
  }
} catch(e) {
  final = { 
    textResponse: builder.error ? '❌ ' + builder.summary : '✅ ' + builder.summary, 
    toolResponse: builder.summary || 'Procesado' 
  };
}

return [{ json: { 
  textResponse: final.textResponse || builder.summary, 
  toolResponse: final.toolResponse || 'Flow procesado', 
  action: builder.action, 
  data: builder.data, 
  chatId: builder.chatId, 
  success: !builder.error 
} }];

// Preparar datos para el agente diseñador
const bridge = $('🔗 Bridge').first().json;

if (!bridge.query || bridge.query.length < 10) {
  return [{ json: { 
    error: true, 
    _action: 'create_workflow', 
    summary: '❌ Necesito más detalles. Describe qué quieres automatizar, qué servicios usar, y qué debe hacer paso a paso.'
  } }];
}

return [{ json: {
  query: bridge.query,
  description: bridge.description || bridge.query,
  chatId: bridge.chatId,
  n8n_host: bridge.n8n_host,
  api_key: bridge.api_key
} }];

const agent = $input.first().json;
const prep = $('🔧 Prep Create WF').first().json;

let wfJson = null;
try {
  let text = agent.output || agent.text || '';

  // Si ya es objeto
  if (typeof text === 'object' && text.nodes) {
    wfJson = text;
  } else {
    // Limpiar markdown
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

    // Extraer JSON
    const m = text.match(/\{[\s\S]*\}/);
    if (m) wfJson = JSON.parse(m[0]);
  }
} catch(e) {
  return [{ json: { 
    error: true, 
    _action: 'create_workflow', 
    summary: '❌ Error generando el workflow: ' + e.message 
  } }];
}

// Validar estructura mínima
if (!wfJson || !wfJson.nodes || !Array.isArray(wfJson.nodes) || wfJson.nodes.length === 0) {
  return [{ json: { 
    error: true, 
    _action: 'create_workflow', 
    summary: '❌ El workflow generado no tiene una estructura válida' 
  } }];
}

// Asegurar que tiene nombre
if (!wfJson.name) {
  wfJson.name = 'Nuevo Workflow ' + new Date().toISOString().slice(0,10);
}

// Asegurar settings
if (!wfJson.settings) {
  wfJson.settings = { executionOrder: 'v1' };
}

// Asegurar connections existe
if (!wfJson.connections) {
  wfJson.connections = {};
}

return [{ json: {
  workflowName: wfJson.name,
  nodeCount: wfJson.nodes.length,
  workflowJson: wfJson,
  n8n_host: prep.n8n_host,
  api_key: prep.api_key
} }];

const createResult = $input.first().json;
const parsed = $('🔧 Parse New WF').first().json;

// Verificar si hubo error
if (createResult.error || createResult.message?.toLowerCase().includes('error')) {
  return [{ json: { 
    error: true, 
    _action: 'create_workflow', 
    summary: '❌ Error creando workflow: ' + (createResult.message || createResult.error || 'Error desconocido')
  } }];
}

// Verificar que se creó (debería tener ID)
if (!createResult.id) {
  return [{ json: { 
    error: true, 
    _action: 'create_workflow', 
    summary: '⚠️ Workflow enviado pero no se recibió confirmación de creación'
  } }];
}

return [{ json: {
  _action: 'create_workflow',
  created: true,
  workflowId: createResult.id,
  workflowName: createResult.name || parsed.workflowName,
  nodeCount: parsed.nodeCount,
  active: createResult.active || false,
  summary: '✅ Workflow "' + (createResult.name || parsed.workflowName) + '" creado exitosamente con ' + parsed.nodeCount + ' nodos. ID: ' + createResult.id + (createResult.active ? ' (activo)' : ' (inactivo - actívalo cuando esté listo)')
} }];

const wf = $input.first().json;
const resolved = $('🔧 Resolve Fix Prompt').first().json;
const bridge = $('🔗 Bridge').first().json;

if (!wf.nodes) {
  return [{ json: { error: true, _action: 'fix_prompt', summary: '❌ Error leyendo workflow' } }];
}

// Buscar el nodo por nombre
const nodeName = resolved.nodeName || '';
let targetNodeIndex = -1;

if (nodeName) {
  targetNodeIndex = wf.nodes.findIndex(n => 
    n.name.toLowerCase().includes(nodeName.toLowerCase())
  );
}

// Si no se especificó nombre, buscar agentes con systemMessage
if (targetNodeIndex === -1) {
  targetNodeIndex = wf.nodes.findIndex(n => 
    n.type?.includes('agent') && n.parameters?.options?.systemMessage
  );
}

if (targetNodeIndex === -1) {
  return [{ json: { 
    error: true, 
    _action: 'fix_prompt', 
    summary: '❌ No se encontró el nodo "' + nodeName + '" o no tiene systemMessage' 
  } }];
}

const targetNode = wf.nodes[targetNodeIndex];
const currentPrompt = targetNode.parameters?.options?.systemMessage || '';
const newContent = resolved.newPrompt || bridge.new_content || '';
const modType = resolved.modificationType || 'append';

// Aplicar modificación
let finalPrompt = currentPrompt;
if (modType === 'append') {
  finalPrompt = currentPrompt + '\n\n' + newContent;
} else if (modType === 'prepend') {
  finalPrompt = newContent + '\n\n' + currentPrompt;
} else {
  finalPrompt = newContent;
}

// ═══ LIMPIAR NODOS - SOLO PROPIEDADES VÁLIDAS ═══
const cleanNodes = wf.nodes.map((node, idx) => {
  const clean = {
    parameters: node.parameters,
    id: node.id,
    name: node.name,
    type: node.type,
    typeVersion: node.typeVersion,
    position: node.position
  };

  // Agregar opcionales solo si existen y tienen valor
  if (node.credentials && Object.keys(node.credentials).length > 0) {
    clean.credentials = node.credentials;
  }
  if (node.webhookId) clean.webhookId = node.webhookId;
  if (node.disabled === true) clean.disabled = true;
  if (node.alwaysOutputData === true) clean.alwaysOutputData = true;
  if (node.retryOnFail === true) clean.retryOnFail = true;
  if (node.continueOnFail === true) clean.continueOnFail = true;
  if (node.notes) clean.notes = node.notes;

  return clean;
});

// Aplicar el cambio del prompt al nodo limpio
cleanNodes[targetNodeIndex].parameters.options.systemMessage = finalPrompt;

// ═══ CONSTRUIR WORKFLOW LIMPIO ═══
const cleanWf = {
  name: wf.name,
  nodes: cleanNodes,
  connections: wf.connections,
  settings: wf.settings || { executionOrder: 'v1' }
};

return [{ json: {
  workflowId: wf.id,
  workflowName: wf.name,
  nodeName: targetNode.name,
  modificationType: modType,
  promptLengthBefore: currentPrompt.length,
  promptLengthAfter: finalPrompt.length,
  modifiedJson: cleanWf
} }];

const wfs = ($input.first().json.data || []);
const bridge = $('🔗 Bridge').first().json;
const search = (bridge.workflow_name || '').toLowerCase();

if (!search) {
  return [{ json: { error: true, _action: 'delete_wf', summary: '❌ No especificaste qué workflow eliminar' } }];
}

const found = wfs.find(w => w.name.toLowerCase().includes(search));
if (!found) {
  return [{ json: { error: true, _action: 'delete_wf', summary: '❌ Workflow no encontrado: ' + search } }];
}

return [{ json: { 
  workflowId: found.id, 
  workflowName: found.name,
  active: found.active
} }];

const resolved = $('🔧 Resolve Delete').first().json;
const deleteResult = $input.first().json;

// Verificar si hubo error
if (deleteResult.error || deleteResult.message?.toLowerCase().includes('error')) {
  return [{ json: { 
    _action: 'delete_wf', 
    error: true, 
    summary: '❌ Error eliminando: ' + (deleteResult.message || 'Error desconocido')
  } }];
}

return [{ json: { 
  _action: 'delete_wf', 
  deleted: true, 
  workflowName: resolved.workflowName,
  workflowId: resolved.workflowId,
  summary: '🗑️ Workflow "' + resolved.workflowName + '" eliminado permanentemente.'
} }];

const resolved = $input.first().json;
const bridge = $('🔗 Bridge').first().json;

if (resolved.error) {
  return [{ json: resolved }];
}

const url = bridge.n8n_host + '/workflow/' + resolved.workflowId;

return [{ json: {
  _action: 'execute_wf',
  name: resolved.workflowName,
  workflowId: resolved.workflowId,
  url: url,
  summary: '🔗 Workflow "' + resolved.workflowName + '" listo. La API pública de n8n no permite ejecución directa. Abre aquí para ejecutarlo: ' + url
} }];

const data = $input.first().json;
return [{ json: {
  _action: 'execute_wf',
  name: data.name || '',
  workflowId: data.workflowId || '',
  url: data.url || '',
  summary: data.summary || ''
} }];

const result = $input.first().json;

if (result.error) {
  return [{ json: { 
    _action: 'update_node', 
    error: true, 
    summary: result.summary || '❌ Error guardando'
  } }];
}

return [{ json: { 
  _action: 'update_node', 
  updated: true, 
  workflowName: result.workflowName,
  nodeName: result.nodeName,
  summary: '✅ Nodo "' + result.nodeName + '" actualizado en "' + result.workflowName + '"'
} }];

const input = $input.first().json;
const bridge = $('🔗 Bridge').first().json;

if (input.error) {
  return [{ json: input }];
}

const body = {
  name: input.modifiedJson.name,
  nodes: input.modifiedJson.nodes,
  connections: input.modifiedJson.connections,
  settings: input.modifiedJson.settings || { executionOrder: 'v1' }
};

try {
  const url = bridge.n8n_host + '/api/v1/workflows/' + input.workflowId;

  const response = await this.helpers.httpRequest({
    method: 'PUT',
    url: url,
    headers: {
      'X-N8N-API-KEY': bridge.api_key,
      'Content-Type': 'application/json'
    },
    body: body
  });

  return [{ json: {
    success: true,
    workflowId: input.workflowId,
    workflowName: input.workflowName,
    nodeName: input.nodeName
  } }];
} catch(e) {
  return [{ json: { 
    error: true, 
    _action: 'update_node', 
    summary: '❌ Error guardando: ' + e.message 
  } }];
}

const wf = $input.first().json;
const resolved = $('🔧 Resolve Update Node').first().json;
const bridge = $('🔗 Bridge').first().json;
const nodeName = (resolved.nodeName || '').toLowerCase();

if (!wf.nodes) {
  return [{ json: { error: true, _action: 'update_node', summary: '❌ Error leyendo workflow' } }];
}

let targetIndex = wf.nodes.findIndex(n => n.name.toLowerCase().includes(nodeName));
if (targetIndex === -1) {
  targetIndex = wf.nodes.findIndex(n => n.type?.includes('agent'));
}
if (targetIndex === -1) {
  return [{ json: { error: true, _action: 'update_node', summary: '❌ Nodo no encontrado: ' + resolved.nodeName } }];
}

const targetNode = wf.nodes[targetIndex];
const query = bridge.query.toLowerCase();

let modificationType = 'unknown';
if (query.includes('tool') || query.includes('herramienta')) {
  modificationType = 'add_tool';
} else if (query.includes('prompt') || query.includes('system')) {
  modificationType = 'modify_prompt';
} else if (query.includes('model') || query.includes('temperatura')) {
  modificationType = 'modify_config';
}

const currentPrompt = targetNode.parameters?.options?.systemMessage || '';

return [{ json: {
  workflowId: resolved.workflowId,
  workflowName: resolved.workflowName,
  targetIndex: targetIndex,
  targetNodeName: targetNode.name,
  targetNodeType: targetNode.type,
  modificationType: modificationType,
  currentPromptPreview: currentPrompt.substring(0, 300),
  query: bridge.query,
  newContent: resolved.newContent,
  fullWorkflow: wf,
  originalNode: targetNode
} }];

const extracted = $('🎯 Extract Target Node').first().json;
const aiResponse = $input.first().json;

if (extracted.error) {
  return [{ json: extracted }];
}

let instruction = {};
try {
  let text = aiResponse.output || aiResponse.text || '';
  if (typeof text === 'object') {
    instruction = text;
  } else {
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*?\}/);
    if (m) instruction = JSON.parse(m[0]);
  }
} catch(e) {
  return [{ json: { error: true, _action: 'update_node', summary: '❌ Error parseando: ' + e.message } }];
}

const wf = extracted.fullWorkflow;
const targetIndex = extracted.targetIndex;
const originalNode = JSON.parse(JSON.stringify(extracted.originalNode));
const action = instruction.action || '';

// ═══ AÑADIR TOOL ═══
if (action === 'add_tool' || action.includes('tool')) {
  const toolType = instruction.tool_type || 'httpRequest';
  const toolName = instruction.tool_name || 'HTTP Browser';

  // Generar ID único para el nuevo nodo
  const newToolId = 'tool-' + Date.now() + '-' + Math.random().toString(36).substring(2, 9);

  // Posición: a la izquierda y abajo del agente
  const agentPos = originalNode.position || [0, 0];
  const toolPos = [agentPos[0] - 200, agentPos[1] + 150];

  // Crear el nodo de herramienta según el tipo
  let newToolNode = null;

  if (toolType === 'httpRequest' || toolType.includes('http') || toolType.includes('browser')) {
    newToolNode = {
      parameters: {
        method: 'GET',
        url: '={{ $json.url || "https://example.com" }}',
        options: {}
      },
      id: newToolId,
      name: '🌐 ' + toolName,
      type: '@n8n/n8n-nodes-langchain.toolHttpRequest',
      typeVersion: 1.1,
      position: toolPos
    };
  } else if (toolType === 'code' || toolType.includes('code')) {
    newToolNode = {
      parameters: {
        jsCode: '// Tool code here\nreturn { result: "ok" };'
      },
      id: newToolId,
      name: '⚡ ' + toolName,
      type: '@n8n/n8n-nodes-langchain.toolCode',
      typeVersion: 1,
      position: toolPos
    };
  } else if (toolType === 'calculator' || toolType.includes('calc')) {
    newToolNode = {
      parameters: {},
      id: newToolId,
      name: '🔢 Calculator',
      type: '@n8n/n8n-nodes-langchain.toolCalculator',
      typeVersion: 1,
      position: toolPos
    };
  } else if (toolType === 'wikipedia' || toolType.includes('wiki')) {
    newToolNode = {
      parameters: {},
      id: newToolId,
      name: '📚 Wikipedia',
      type: '@n8n/n8n-nodes-langchain.toolWikipedia',
      typeVersion: 1,
      position: toolPos
    };
  } else {
    // Default: HTTP Request tool
    newToolNode = {
      parameters: {
        method: 'GET',
        url: '={{ $json.url || "https://example.com" }}',
        options: {}
      },
      id: newToolId,
      name: '🌐 ' + toolName,
      type: '@n8n/n8n-nodes-langchain.toolHttpRequest',
      typeVersion: 1.1,
      position: toolPos
    };
  }

  // Añadir el nodo al workflow
  wf.nodes.push(newToolNode);

  // Añadir la conexión: Tool → Agente (ai_tool)
  if (!wf.connections[newToolNode.name]) {
    wf.connections[newToolNode.name] = {};
  }
  wf.connections[newToolNode.name].ai_tool = [
    [{ node: originalNode.name, type: 'ai_tool', index: 0 }]
  ];

  // Limpiar y devolver
  const cleanNodes = wf.nodes.map(node => {
    const clean = {
      parameters: node.parameters,
      id: node.id,
      name: node.name,
      type: node.type,
      typeVersion: node.typeVersion,
      position: node.position
    };
    if (node.credentials) clean.credentials = node.credentials;
    if (node.webhookId) clean.webhookId = node.webhookId;
    return clean;
  });

  return [{ json: { 
    workflowId: extracted.workflowId, 
    workflowName: extracted.workflowName, 
    nodeName: extracted.targetNodeName,
    toolAdded: newToolNode.name,
    modifiedJson: {
      name: wf.name,
      nodes: cleanNodes,
      connections: wf.connections,
      settings: wf.settings || { executionOrder: 'v1' }
    }
  } }];
}

// ═══ MODIFICAR PROMPT ═══
if (action === 'modify_prompt' || action.includes('prompt')) {
  const currentPrompt = originalNode.parameters?.options?.systemMessage || '';
  const mod = instruction.modification || 'append';
  const content = instruction.content || '';

  let newPrompt = currentPrompt;
  if (mod === 'append') newPrompt = currentPrompt + '\n\n' + content;
  else if (mod === 'prepend') newPrompt = content + '\n\n' + currentPrompt;
  else newPrompt = content;

  if (!originalNode.parameters.options) originalNode.parameters.options = {};
  originalNode.parameters.options.systemMessage = newPrompt;
  wf.nodes[targetIndex] = originalNode;
}

// ═══ MODIFICAR CONFIG ═══
if (action === 'modify_config' || action.includes('config')) {
  const changes = instruction.changes || {};
  Object.keys(changes).forEach(key => {
    if (originalNode.parameters?.options) {
      originalNode.parameters.options[key] = changes[key];
    }
  });
  wf.nodes[targetIndex] = originalNode;
}

// Limpiar nodos
const cleanNodes = wf.nodes.map(node => {
  const clean = {
    parameters: node.parameters,
    id: node.id,
    name: node.name,
    type: node.type,
    typeVersion: node.typeVersion,
    position: node.position
  };
  if (node.credentials) clean.credentials = node.credentials;
  if (node.webhookId) clean.webhookId = node.webhookId;
  return clean;
});

return [{ json: { 
  workflowId: extracted.workflowId, 
  workflowName: extracted.workflowName, 
  nodeName: extracted.targetNodeName,
  modifiedJson: {
    name: wf.name,
    nodes: cleanNodes,
    connections: wf.connections,
    settings: wf.settings || { executionOrder: 'v1' }
  }
} }];
